'use client'

import React, { useState, useRef } from 'react';
import { Shield, HardHat, Footprints, Eye, Smartphone, Activity, Zap, HandFist, HandFistIcon } from 'lucide-react';

interface DetectionClass {
  id: string;
  label: string;
  enabled: boolean;
  icon: React.ReactNode;
}

const SafetyDashboard: React.FC = () => {
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const [isStreaming, setIsStreaming] = useState(false);
  
  // State for detection toggles
  const [classes, setClasses] = useState<DetectionClass[]>([
    { id: 'helmet', label: 'Helmet', enabled: true, icon: <HardHat size={18} /> },
    { id: 'boots', label: 'Boots', enabled: true, icon: <Footprints size={18} /> },
    { id: 'glasses', label: 'Safety Glasses', enabled: false, icon: <Eye size={18} /> },
    { id: 'gloves', label: 'Gloves', enabled: false, icon: <HandFist size={18} /> },
    { id: 'vest', label: 'Safety Vest', enabled: true, icon: <Shield size={18} /> },
    { id: 'phones', label: 'Phones', enabled: false, icon: <Smartphone size={18} /> },
  ]);

  const toggleClass = (id: string) => {
    setClasses(prev => prev.map(c => 
      c.id === id ? { ...c, enabled: !c.enabled } : c
    ));
  };

  const startStream = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsStreaming(true);
      }
    } catch (err) {
      console.error("Camera access denied", err);
    }
  };

  const stopStream = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      videoRef.current.srcObject = null;
      setIsStreaming(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-[#e0e0e0] flex items-center justify-center p-4 font-sans">
      <div className="w-full max-w-6xl bg-[#141414] border border-[#333] rounded-xl shadow-2xl flex flex-col md:flex-row overflow-hidden">
        
        {/* Sidebar */}
        <aside className="w-full md:w-64 border-r border-[#333] p-6 bg-[#0f0f0f]">
          <h2 className="text-xs font-bold uppercase tracking-widest text-gray-500 mb-6">
            Detection Filters
          </h2>
          <div className="space-y-3">
            {classes.map((item) => (
              <div key={item.id} className="flex items-center justify-between bg-[#1a1a1a] p-3 rounded-lg border border-[#222]">
                <div className="flex items-center gap-3">
                  <span className={item.enabled ? "text-green-500" : "text-gray-600"}>
                    {item.icon}
                  </span>
                  <span className="text-sm font-medium">{item.label}</span>
                </div>
                <button
                  onClick={() => toggleClass(item.id)}
                  className={`relative inline-flex h-5 w-10 items-center rounded-full transition-colors duration-300 ${
                    item.enabled ? 'bg-green-500 shadow-[0_0_10px_rgba(46,204,113,0.5)]' : 'bg-gray-700'
                  }`}
                >
                  <span
                    className={`inline-block h-3 w-3 transform rounded-full bg-white transition-transform duration-300 ${
                      item.enabled ? 'translate-x-6' : 'translate-x-1'
                    }`}
                  />
                </button>
              </div>
            ))}
          </div>
        </aside>

        {/* Main Feed Area */}
        <main className="flex-1 p-6 flex flex-col">
          <header className="flex justify-between items-center mb-4 border-b border-[#333] pb-4">
            <div className="flex items-center gap-2">
              <div className={`h-2 w-2 rounded-full ${isStreaming ? 'bg-green-500 animate-pulse shadow-[0_0_8px_#2ecc71]' : 'bg-red-500'}`} />
              <span className="text-sm font-semibold tracking-wide">LIVE_FEED // SECTOR_01</span>
            </div>
            <span className="text-[10px] text-gray-500 font-mono">YOLOv8_ENGINE_ACTIVE</span>
          </header>

          <div className="relative aspect-video bg-black rounded-lg border border-[#333] overflow-hidden flex items-center justify-center">
            {!isStreaming && (
              <div className="text-gray-600 flex flex-col items-center gap-2 uppercase text-xs tracking-tighter">
                <Activity className="opacity-20" size={48} />
                Awaiting Signal...
              </div>
            )}
            <video
              ref={videoRef}
              autoPlay
              playsInline
              className={`w-full h-full object-cover ${isStreaming ? 'opacity-100' : 'opacity-0'}`}
            />
          </div>

          {/* Action Buttons */}
          <footer className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-6">
            <button 
              onClick={startStream}
              className="bg-[#1a1a1a] border border-[#333] py-3 px-4 rounded hover:bg-green-500 hover:text-black transition-all font-bold text-[10px] uppercase tracking-widest"
            >
              Initiate
            </button>
            <button className="bg-[#1a1a1a] border border-[#333] py-3 px-4 rounded hover:border-green-500 transition-all font-bold text-[10px] uppercase tracking-widest">
              Telemetry
            </button>
            <button className="bg-[#1a1a1a] border border-[#333] py-3 px-4 rounded hover:border-green-500 transition-all font-bold text-[10px] uppercase tracking-widest">
              Diagnostics
            </button>
            <button 
              onClick={stopStream}
              className="border border-red-900/50 text-red-500 py-3 px-4 rounded hover:bg-red-600 hover:text-white transition-all font-bold text-[10px] uppercase tracking-widest"
            >
              Abort
            </button>
          </footer>
        </main>
      </div>
    </div>
  );
};

export default SafetyDashboard;